const base = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const key = $env.SUPABASE_SERVICE_ROLE_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZS1kZW1vIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImV4cCI6MTk4MzgxMjk5Nn0.EGIM96RAZx35lJzdJsyH-qQwv8Hdp7fsn3W0YpN81IU';
const PILOT_CLINIC = '51738ea8-c12e-40ce-a0e2-42869496d76b';
const m = $('Mesaj Normalize').first().json;
const headers = { apikey: key, Authorization: `Bearer ${key}` };
let CLINIC_ID = PILOT_CLINIC;
const instanceName = String(m.instance || $env.EVOLUTION_INSTANCE || 'medident-pilot').trim();
if (instanceName) {
  const clinics = await this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/rest/v1/clinics?evolution_instance_name=eq.${encodeURIComponent(instanceName)}&select=id&limit=1`,
    headers,
    json: true,
  });
  if (Array.isArray(clinics) && clinics[0]?.id) CLINIC_ID = clinics[0].id;
}
const phone = String(m.phone || '').replace(/\D/g, '');
const currentMsg = String(m.message || '').trim();
let rows = [];
if (phone) {
  rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/rest/v1/inbox_messages?clinic_id=eq.${CLINIC_ID}&sender_phone=eq.${phone}&channel=eq.whatsapp&order=created_at.desc&limit=12`,
    headers,
    json: true,
  });
}

const cutoff = Date.now() - 45000;
const recentInbound = rows
  .filter((r) => r.direction === 'inbound' && new Date(r.created_at).getTime() >= cutoff)
  .map((r) => String(r.body || '').trim())
  .filter(Boolean)
  .reverse();

const burst = [...recentInbound];
if (!burst.length || burst[burst.length - 1] !== currentMsg) burst.push(currentMsg);
const mergedMessage = burst.join(' ').trim() || currentMsg;

const older = rows.filter((r) => new Date(r.created_at).getTime() < cutoff).slice(0, 10).reverse();
const historyLines = [];
for (const r of older) {
  if (r.direction === 'inbound') historyLines.push(`Hasta: ${r.body}`);
  else historyLines.push(`Klinik: ${r.body}`);
  if (r.direction === 'inbound' && r.ai_draft_reply && r.status === 'replied') {
    historyLines.push(`Klinik: ${r.ai_draft_reply}`);
  }
}
const historyText = historyLines.length ? historyLines.join('\n') : '— (ilk mesaj)';


return [{
  json: {
    ...m,
    clinic_id: CLINIC_ID,
    instance: instanceName,
    message: mergedMessage,
    originalMessage: currentMsg,
    historyText,
    historyCount: older.length,
  },
}];

